Функция ПолучитьДоговорДействующийНа(Контрагент, ДатаСреза)
	// Проверки входных параметров
	Если ТипЗнч(Контрагент) = Тип("Null") Или ТипЗнч(ДатаСреза) = Тип("Null") Тогда
		Возврат Неопределено;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ ПЕРВЫЕ 1
		Договор.Ссылка КАК Договор
	ИЗ
		Справочник.Договоры КАК Договор
	ГДЕ
		Договор.Владелец = &Контрагент
		И Договор.ДатаНачала <= &ДатаСреза
		И (Договор.ДатаОкончания >= &ДатаСреза ИЛИ Договор.ДатаОкончания ЕСТЬ NULL)
	УПОРЯДОЧИТЬ ПО
		Договор.ДатаНачала УБЫВ";

	Запрос.УстановитьПараметр("Контрагент", Контрагент);
	Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

	Результат = Запрос.Выполнить().Выбрать();
	Если Результат.Следующий() Тогда
		Возврат Результат.Договор;
	Иначе
		Возврат Неопределено;
	КонецЕсли;
КонецФункции
